import React from "react";

export default function Forecast({ data = [] }) {
  const days = Array.isArray(data) ? data.slice(0, 16) : [];

  return (
    <div className="w-full">
      <div className="flex flex-col space-y-3 md:space-y-2">
        {days.map((d, i) => {
          const dt = d?.dt ? new Date(d.dt * 1000) : new Date(Date.now() + (i + 1) * 86400000);
          const day = dt.toLocaleDateString(undefined, { weekday: "short" });
          const high = d?.temp?.max != null ? Math.round(d.temp.max) : "—";
          const low  = d?.temp?.min != null ? Math.round(d.temp.min) : "—";
          const icon = d?.weather?.[0]?.icon || "⛅";
          const desc = d?.weather?.[0]?.description || "—";

          return (
            <div
              key={i}
              className="w-full rounded-2xl bg-white/20 backdrop-blur border border-white/20
                         px-4 py-3 flex items-center justify-between shadow-sm md:rounded-xl"
            >
              <div className="flex items-center gap-3">
                <span className="text-base md:text-sm font-medium">{day}</span>
                <span className="text-xl md:text-lg">{icon}</span>
                <span className="text-sm md:text-xs opacity-80 capitalize">{desc}</span>
              </div>
              <div className="flex items-center gap-2">
                <span className="text-sm md:text-xs">{high}°</span>
                <span className="text-xs md:text-[11px] opacity-70">/ {low}°</span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
